/bin/zsh -lc "python - <<'PY'
import csv, json
from pathlib import Path


def parse_bool(value):
    return value.strip().lower() == 'true'


def calc_credit(c):
    income = c['monthly_income']
    emp = c['employment_years']
    debt = c['debt_ratio']
    age = c['age']
    defaults = c['past_defaults']

    if income >= 50000:
        pts_inc = 60
    elif income >= 20000:
        pts_inc = 50
    elif income >= 10000:
        pts_inc = 35
    elif income >= 5000:
        pts_inc = 20
    else:
        pts_inc = 10

    if emp >= 10:
        pts_emp = 40
    elif emp >= 5:
        pts_emp = 35
    elif emp >= 3:
        pts_emp = 25
    elif emp >= 1:
        pts_emp = 15
    else:
        pts_emp = 5

    if debt < 20:
        pts_debt = 30
    elif debt <= 40:
        pts_debt = 20
    elif debt <= 60:
        pts_debt = 10
    else:
        pts_debt = 0

    pts_asset = (10 if c['has_mortgage'] else 0) + (-5 if c['has_car_loan'] else 0)

    if age < 25:
        pts_age = -5
    elif age <= 35:
        pts_age = 10
    elif age <= 50:
        pts_age = 15
    else:
        pts_age = 5

    if defaults == 0:
        pts_def = 20
    elif defaults == 1:
        pts_def = 5
    else:
        pts_def = -10

    score = pts_inc + pts_emp + pts_debt + pts_asset + pts_age + pts_def

    if score >= 120:
        return {'score': score, 'tier': 'Excellent', 'max_loan': 500000, 'rate': '3.5%'}
    if score >= 90:
        return {'score': score, 'tier': 'Good', 'max_loan': 300000, 'rate': '5.0%'}
    if score >= 60:
        return {'score': score, 'tier': 'Fair', 'max_loan': 100000, 'rate': '7.5%'}
    return {'score': score, 'tier': 'Poor', 'max_loan': 0, 'rate': 'N/A'}

rows = []
with Path('input.csv').open(newline='', encoding='utf-8') as f:
    for row in csv.DictReader(f):
        customer = {
            'monthly_income': float(row['monthly_income']),
            'employment_years': float(row['employment_years']),
            'debt_ratio': float(row['debt_ratio']),
            'has_mortgage': parse_bool(row['has_mortgage']),
            'has_car_loan': parse_bool(row['has_car_loan']),
            'age': float(row['age']),
            'past_defaults': int(row['past_defaults']),
        }
        result = calc_credit(customer)
        rows.append({
            'id': row['id'],
            'score': int(result['score']),
            'tier': result['tier'],
            'max_loan': result['max_loan'],
            'rate': result['rate'],
        })

Path('output.json').write_text(json.dumps(rows, ensure_ascii=False, indent=2) + '\\n', encoding='utf-8')
PY"

